// Time:  O(n)
// Space: O(1)

class Solution {
public:
    ListNode* reverseEvenLengthGroups(ListNode* head) {
        auto prev = head;
        int l = 2;
        while (prev->next) {
            auto curr = prev;
            int cnt = 0;
            for (; cnt < l && curr->next; ++cnt, curr = curr->next);
            ++l;
            if (cnt % 2) {
                prev = curr;
                continue;
            }
            curr = prev->next;
            ListNode *last = nullptr;
            while (cnt--) {
                auto nxt = curr->next;
                curr->next = last;
                last = curr;
                curr = nxt;
            }
            auto tail = prev->next;
            tail->next = curr;
            prev->next = last;
            prev = tail;
        }
        return head;
    }
};

# Time:  O(n)
# Space: O(1)

class ListNode(object):
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next


class Solution(object):
    def reverseEvenLengthGroups(self, head):
        """
        :type head: Optional[ListNode]
        :rtype: Optional[ListNode]
        """
        prev, l = head, 2
        while prev.next:
            curr, cnt = prev, 0
            for _ in xrange(l):
                if not curr.next:
                    break
                cnt += 1
                curr = curr.next
            l += 1
            if cnt%2:
                prev = curr
                continue
            curr, last = prev.next, None
            for _ in xrange(cnt):
                curr.next, curr, last = last, curr.next, curr
            prev.next.next, prev.next, prev = curr, last, prev.next
        return head
